select id, notice_title, notice_type, notice_content, sort, is_deleted, sn.status,su.nick_name as create_user, su2.nick_name as update_user, sn.create_time,sn.update_time from shop_notice sn left join sys_user su on sn.create_user = su.user_id left join sys_user su2 on sn.update_user = su2.user_id where 1 = 1 and is_deleted = 0
and notice_title like concat('%','公告','%')
and notice_type = #{dto.noticeType}
and sn.`status` = #{dto.status}
order by sort, create_time desc

select id, notice_title, notice_type, notice_content, sort, is_deleted, sn.status, sn.create_time,sn.update_time from shop_notice sn where 1 = 1 and is_deleted = 0
and notice_title like concat('%','公告','%')
and notice_type = #{dto.noticeType}
and sn.`status` = #{dto.status}
order by sort, create_time desc
